class TodoTracker:
    """Wrapper for XTCode main.py compatibility."""
    def __init__(self):
        self.items = []

    def handle(self, action, text="", priority="medium", index=0):
        if action == "add":
            return todo_add(text, priority)
        elif action == "list":
            return todo_list()
        elif action == "done":
            return todo_done(index)
        elif action == "clear":
            return todo_clear()
        return "Unknown todo action"
